INSERT INTO `employee_memos` (`id`, `user_id`, `employee_id`, `office_id`, `issued_by`, `violation_code`, `violation_name`, `offense_number`, `consequence`, `consequence_type`, `suspension_days`, `suspension_start`, `suspension_end`, `memo_notes`, `status`, `created_at`, `updated_at`) VALUES
	(23, 150, 162, 5, 144, 'A-01', 'Late login / late arrival', 1, 'Verbal warning', 'warning', NULL, NULL, NULL, 'Subject: Formal Notice: Late Login/Arrival (Code A-01)\n\nDear Altamera, CJ,\n\nThis letter serves as formal notice of your violation of Code A-01. On April 20, 2026, you reported to work at , which is past your scheduled shift start. Punctuality is a requirement of your role, and this incident has been documented in your 201 file.', 'resolved', '2026-04-20 09:48:56', '2026-04-20 09:48:56'),
	(24, 150, 162, 5, 144, 'A-01', 'Late login / late arrival', 2, 'Written warning', 'warning', NULL, NULL, NULL, 'Subject: Formal Notice: Late Login/Arrival (Code A-01)\n\nDear Altamera, CJ,\n\nThis letter serves as formal notice of your violation of Code A-01. On April 20, 2026, you reported to work at , which is past your scheduled shift start. Punctuality is a requirement of your role, and this incident has been documented in your 201 file.', 'resolved', '2026-04-20 09:49:01', '2026-04-20 09:49:01'),
	(25, 150, 162, 5, 144, 'A-01', 'Late login / late arrival', 3, 'Final warning', 'warning', NULL, NULL, NULL, 'Subject: Formal Notice: Late Login/Arrival (Code A-01)\n\nDear Altamera, CJ,\n\nThis letter serves as formal notice of your violation of Code A-01. On April 20, 2026, you reported to work at , which is past your scheduled shift start. Punctuality is a requirement of your role, and this incident has been documented in your 201 file.', 'resolved', '2026-04-20 09:49:05', '2026-04-20 09:49:05'),
	(26, 150, 162, 5, 144, 'A-01', 'Late login / late arrival', 4, 'Suspension up to 3 days', 'suspension', 3, '2026-04-20', '2026-04-22', 'Subject: Formal Notice: Late Login/Arrival (Code A-01)\n\nDear Altamera, CJ,\n\nThis letter serves as formal notice of your violation of Code A-01. On April 20, 2026, you reported to work at , which is past your scheduled shift start. Punctuality is a requirement of your role, and this incident has been documented in your 201 file.', 'resolved', '2026-04-20 09:49:08', '2026-04-20 09:50:46'),
	(27, 150, 162, 5, 144, 'DP-01', 'Sharing confidential info', 1, 'Termination', 'termination', NULL, NULL, NULL, 'Subject: Notice of Immediate Termination (Code DP-01)\n\nDear Altamera, CJ,\n\nThis letter serves as formal notification that your employment is terminated effective immediately. An investigation has confirmed that you violated Code DP-01 by sharing confidential company or client information. This breach of our data privacy agreement warrants immediate dismissal for cause.', 'resolved', '2026-04-22 19:05:47', '2026-04-22 19:07:56');
