	(1, 'A-01', 'Late login / late arrival', 3, 'Verbal warning', 'warning', 0, 'Written warning', 'warning', 0, 'Final warning', 'warning', 0, 'Suspension up to 3 days', 'suspension', 3, 1, '2026-04-15 19:43:27', '2026-04-16 19:09:17'),
